{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization and search problem involving spatial reasoning, uncertainty (noisy queries), and cost minimization. I will decompose it into tasks that handle spatial modeling, query strategy optimization, and cost estimation.",
  "helpers": [
    {
      "label": "spatial_modeler",
      "instructions": "Given the set of known polyomino shapes and the grid dimensions, generate all possible valid placements (translations/rotations/reflections) for each polyomino shape that fit within the grid boundaries."
    },
    {
      "label": "query_optimizer",
      "instructions": "Develop a strategy to select drilling locations and aggregate query regions. The strategy should prioritize areas with high overlap of potential polyomino placements to maximize information gain per unit cost, accounting for the 'noisy' nature of the aggregate queries."
    },
    {
      "label": "probabilistic_inference",
      "instructions": "Given a set of query results (drilling hits/misses and noisy aggregate counts), calculate the posterior probability for each cell being part of an oil-containing polyomino. Use a Bayesian approach to update the likelihood of specific polyomino placements based on the observed data."
    },
    {
      "label": "cost_evaluator",
      "instructions": "Implement a function to calculate the total probing cost (drilling cost + aggregate query cost + final guess cost) for a given sequence of actions and a resulting set of identified cells, comparing it against the theoretical minimum cost."
    }
  ],
  "synthesis_brief": "The parent node will use the spatial_modeler to define the search space, the query_optimizer to decide the sequence of probes, the probabilistic_inference engine to interpret the results of those probes to narrow down the possible polyomino configurations, and finally, the cost_evaluator to ensure the chosen strategy minimizes the total cost before outputting the final set of oil-containing cells."
}
```

